import json

# Get LA businesses and reviews
la_businesses = locals()['var_functions.query_db:44']
all_reviews = locals()['var_functions.query_db:45']

# Convert ratings to integers
reviews_clean = []
for review in all_reviews:
    try:
        # Handle case where rating might be string
        rating = int(review.get('rating', 0))
        reviews_clean.append({
            'gmap_id': review['gmap_id'],
            'rating': rating
        })
    except:
        pass

# Get LA business IDs
la_gmap_ids = {biz['gmap_id'] for biz in la_businesses}
business_names = {biz['gmap_id']: biz['name'] for biz in la_businesses}

# Filter reviews for LA businesses
la_reviews = [r for r in reviews_clean if r['gmap_id'] in la_gmap_ids]

print(f'Found {len(la_businesses)} LA businesses')
print(f'Found {len(la_reviews)} reviews for LA businesses')
print('__RESULT__:')
print(json.dumps({
    'business_count': len(la_businesses),
    'review_count': len(la_reviews),
    'business_ids': list(la_gmap_ids)
}))

